var e=[{id:`L2_1`,type:`dialog`,speaker:`MATCHMAN_NPC_NULL_NULL`,text:{KOREA:`커억......! 헉......! 허억......!`,JPN:`ガハッ……！　くっ……！　ぐは……！`,ENG:`Ack! Hngh! Huff!`,TWN:`呃……！咳……！咳……！`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`MATCHMAN_NPC_NULL_NULL`,text:{KOREA:`숨이...... 안 쉬어져......`,JPN:`息が……できない……`,ENG:`I can't... breathe...`,TWN:`我……不能呼吸……`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MATCHMAN_NPC_NULL_NULL`,text:{KOREA:`빌어먹을...... 어디서 이런...... 괴물 같은 꼬맹이가 나타나서......`,JPN:`くそっ……どこからこんな……化け物みたいなガキが……`,ENG:`Drat it... Where the hell did they find this little monster?`,TWN:`該死……從哪裡冒出了……這種怪物……`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`일어나, 이 개자식아!`,JPN:`起きろ、このカス野郎！`,ENG:`Get up, you bastard!`,TWN:`起來，狗東西！`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`MATCHMAN_NPC_NULL_NULL`,text:{KOREA:`크윽......`,JPN:`くうっ……`,ENG:`Hngh...`,TWN:`嚇呃……`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`네가 여태까지 저지른 잘못들은 따지기도 지긋지긋해.`,JPN:`お前がこれまで犯した過ちを問い詰める時間すら勿体ない。`,ENG:`I can't even begin to list all the evils you've committed.`,TWN:`你犯下的罪過太多，數也數不完。`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`그러니 하나만 말해.`,JPN:`だから一つだけ答えろ。`,ENG:`So I'll just ask about one.`,TWN:`所以你只需告訴我一件事情就可以。`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`어째서...... 어째서 내 가족들을 죽인 거야?`,JPN:`どうして……どうして私の家族を殺した？`,ENG:`Why... Why did you kill my family?`,TWN:`為什麼……為什麼殺了我的家人？`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`MATCHMAN_NPC_NULL_NULL`,text:{KOREA:`죽였다고......? 큭...... 내가?`,JPN:`殺したって？　クク……俺が？`,ENG:`I killed... who? Hah... Me?`,TWN:`殺了你家人……？咳……我？`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`시치미 떼지 마!`,JPN:`しらばっくれるな！`,ENG:`Don't play dumb with me!`,TWN:`別裝蒜！`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`집이 불타던 그날 똑똑히 봤어! 시간이 지났다고 내가 잊을 줄 알았냐?!`,JPN:`家が燃えたあの日、この目で見た！　時間が経ったからって忘れたとでも思ったのか？`,ENG:`I saw you that day when my house was on fire! Did you think I'd forget it after all these years?`,TWN:`房子被燒的那天，我看得一清二楚！你以為時間會洗掉我的記憶嗎？！`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MATCHMAN_NPC_NULL_NULL`,text:{KOREA:`집이 불타......? 대체 무슨 소리를......`,JPN:`家が燃える……？　いったい何のこと……`,ENG:`Fire? What house? What the hell are you talking about—`,TWN:`房子被燒……？到底在說什麼……`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`MATCHMAN_NPC_NULL_NULL`,text:{KOREA:`아, 하핫......! 하하하하핫!`,JPN:`ああ、ハハ！　アハハハハ！`,ENG:`Oh... Hah hah... Hah hah hah hah!`,TWN:`啊，哈哈……！哈哈哈哈哈！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`MATCHMAN_NPC_NULL_NULL`,text:{KOREA:`크큭, 끝내 주는군......! 정말, 쿨럭!! 끝내 줘......!`,JPN:`ククク、最高だな……！　実に、ゲホッ！！　笑わせてくれる……！`,ENG:`Hah, Incredible... This is really... *Cough*... incredible!`,TWN:`咳咳，棒極了……！真的，咳咳！！棒極了……！`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`웃지 마! 내 질문에 대답해!`,JPN:`笑ってんじゃない！　質問に答えろ！`,ENG:`Stop laughing and answer me!`,TWN:`別笑！快回答我！`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`MATCHMAN_NPC_NULL_NULL`,text:{KOREA:`아, 그래. 그 꼬마였군. 기억나.`,JPN:`ああ、そうか。あの時のお嬢ちゃんか。思い出した。`,ENG:`Ah, I see. So you were that little kid. I remember now.`,TWN:`啊，沒錯。我記得，原來是那個小孩。`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`MATCHMAN_NPC_NULL_NULL`,text:{KOREA:`하지만 완전히 잘못 짚었다, 꼬마야.`,JPN:`しかし勘違いしてるぞ、ガキ。`,ENG:`But you've got it all wrong, little one.`,TWN:`但你找錯人了，孩子。`},stage:{bg:`SS_MILITIA_08`,slots:{L:null,C:null,R:null}}}];export{e as default};